class Solution:
  def isValidTag(self, tagName: str) -> bool:
    if len(tagName) > 40:
      return False
    if not tagName.startswith('v'):
      return False
    pattern = r'^[a-zA-Z0-9][a-zA-Z0-9.-]{0,38}$'
    import re
    return bool(re.match(pattern, tagName))
